import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import AuthLayout from '../components/auth/AuthLayout';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [adminSecret, setAdminSecret] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const { login, logout } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const role = isAdmin ? 'admin' : 'student';
    try {
      const data = await login(email, password, role, isAdmin ? adminSecret : undefined);
      if (isAdmin && data.user.role !== 'admin') {
        logout();
        setError('This account is not registered as an administrator.');
        return;
      }
      if (!isAdmin && data.user.role !== 'student') {
        logout();
        setError('This account is not registered as a student. Use the student login.');
        return;
      }
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout
      title="Sign In"
      subtitle="Enter your KEC credentials to access the portal"
      footerLink={{ text: "New student?", to: '/signup', label: 'Register here' }}
    >
      {/* Role Toggle */}
      <div className="role-tabs">
        <button
          type="button"
          className={`role-tab ${!isAdmin ? 'active' : ''}`}
          onClick={() => { setIsAdmin(false); setError(''); }}
        >
          🎓 Student
        </button>
        <button
          type="button"
          className={`role-tab ${isAdmin ? 'active' : ''}`}
          onClick={() => { setIsAdmin(true); setError(''); }}
        >
          🛠️ Administrator
        </button>
      </div>

      {error && (
        <div className="login-error">
          <span>⚠️</span>
          <span>{error}</span>
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>College Email</label>
          <input
            type="email"
            value={email}
            onChange={e => setEmail(e.target.value)}
            placeholder={isAdmin ? 'admin@kec.ac.in' : 'rollno@kec.ac.in'}
            required
            autoComplete="email"
          />
        </div>
        <div className="form-group">
          <label>Password</label>
          <div className="input-wrap">
            <input
              type={showPass ? 'text' : 'password'}
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
              autoComplete="current-password"
            />
            <button type="button" className="toggle-pass" onClick={() => setShowPass(!showPass)}>
              {showPass ? 'Hide' : 'Show'}
            </button>
          </div>
        </div>

        {isAdmin && (
          <div className="form-group">
            <label>Administrator Access Code</label>
            <input
              type="password"
              value={adminSecret}
              onChange={e => setAdminSecret(e.target.value)}
              placeholder="Enter admin access code"
              required
            />
            <small className="field-hint">Contact the IT department if you've forgotten your access code.</small>
          </div>
        )}

        <button
          type="submit"
          id="login-submit-btn"
          className="btn btn-primary btn-lg login-submit"
          disabled={loading}
        >
          {loading ? (
            <><span className="spinner spinner-sm" /> Signing in...</>
          ) : (
            `Sign In as ${isAdmin ? 'Administrator' : 'Student'}`
          )}
        </button>
      </form>

      <div style={{ marginTop: 20, padding: 14, background: 'var(--surface2)', borderRadius: 'var(--radius-sm)', border: '1px solid var(--border)', fontSize: 12, color: 'var(--text-muted)' }}>
        <strong style={{ display: 'block', marginBottom: 4, color: 'var(--text)' }}>🔒 Secure Portal</strong>
        This portal is managed by the KEC Transportation Department. 
        For registration or password issues, please contact: <strong>transport@kec.ac.in</strong>
      </div>
    </AuthLayout>
  );
}
